ll power(ll a, ll b, ll mod = MOD) {
    ll res = 1;
    while (b) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

// Modular inverse (only if mod is prime)
ll modinv(ll a, ll mod = MOD) {
    return power(a, mod - 2, mod);
}

